450	function resolveChatChannelSecurity<TResolvedAccount extends { accountId?: string | null }>(
451	  security:
452	    | ChannelSecurityAdapter<TResolvedAccount>
453	    | ChatChannelSecurityOptions<TResolvedAccount>
454	    | undefined,
455	): ChannelSecurityAdapter<TResolvedAccount> | undefined {
456	  if (!security) {
457	    return undefined;
458	  }
459	  if (!("dm" in security)) {
460	    return security;
461	  }
462	  return {
463	    resolveDmPolicy: ({ cfg, accountId, account }) =>
464	      buildAccountScopedDmSecurityPolicy({
465	        cfg,
466	        channelKey: security.dm.channelKey,
467	        accountId,
468	        fallbackAccountId: security.dm.resolveFallbackAccountId?.(account) ?? account.accountId,
469	        policy: security.dm.resolvePolicy(account),
470	        allowFrom: security.dm.resolveAllowFrom(account) ?? [],
471	        defaultPolicy: security.dm.defaultPolicy,
472	        allowFromPathSuffix: security.dm.allowFromPathSuffix,
473	        policyPathSuffix: security.dm.policyPathSuffix,
474	        approveChannelId: security.dm.approveChannelId,
475	        approveHint: security.dm.approveHint,
476	        normalizeEntry: security.dm.normalizeEntry,
477	      }),
478	    ...(security.collectWarnings ? { collectWarnings: security.collectWarnings } : {}),
479	  };
480	}
481	
482	function resolveChatChannelPairing(
483	  pairing: ChannelPairingAdapter | ChatChannelPairingOptions | undefined,
484	): ChannelPairingAdapter | undefined {
485	  if (!pairing) {
486	    return undefined;
487	  }
488	  if (!("text" in pairing)) {
489	    return pairing;
490	  }
491	  return createInlineTextPairingAdapter(pairing.text);
492	}
493	
494	function resolveChatChannelThreading<TResolvedAccount>(
495	  threading: ChannelThreadingAdapter | ChatChannelThreadingOptions<TResolvedAccount> | undefined,
496	): ChannelThreadingAdapter | undefined {
497	  if (!threading) {
498	    return undefined;
499	  }
500	  if (!("topLevelReplyToMode" in threading) && !("scopedAccountReplyToMode" in threading)) {
501	    return threading;
502	  }
503	
504	  let resolveReplyToMode: ChannelThreadingAdapter["resolveReplyToMode"];
505	  if ("topLevelReplyToMode" in threading) {
506	    resolveReplyToMode = createTopLevelChannelReplyToModeResolver(threading.topLevelReplyToMode);
507	  } else {
508	    resolveReplyToMode = createScopedAccountReplyToModeResolver<TResolvedAccount>(
509	      threading.scopedAccountReplyToMode,
510	    );
511	  }
512	
513	  return {
514	    ...threading,
515	    resolveReplyToMode,
516	  };
517	}
518	
519	function resolveChatChannelOutbound(
520	  outbound: ChannelOutboundAdapter | ChatChannelAttachedOutboundOptions | undefined,
521	): ChannelOutboundAdapter | undefined {
522	  if (!outbound) {
523	    return undefined;
524	  }
525	  if (!("attachedResults" in outbound)) {
526	    return outbound;
527	  }
528	  return {
529	    ...outbound.base,
530	    ...createInlineAttachedChannelResultAdapter(outbound.attachedResults),
531	  };
532	}
533	
534	// Shared higher-level builder for chat-style channels that mostly compose
535	// scoped DM security, text pairing, reply threading, and attached send results.
536	export function createChatChannelPlugin<
537	  TResolvedAccount extends { accountId?: string | null },
538	  Probe = unknown,
539	  Audit = unknown,
540	>(params: {
541	  base: ChatChannelPluginBase<TResolvedAccount, Probe, Audit>;
542	  security?:
543	    | ChannelSecurityAdapter<TResolvedAccount>
544	    | ChatChannelSecurityOptions<TResolvedAccount>;
545	  pairing?: ChannelPairingAdapter | ChatChannelPairingOptions;
546	  threading?: ChannelThreadingAdapter | ChatChannelThreadingOptions<TResolvedAccount>;
547	  outbound?: ChannelOutboundAdapter | ChatChannelAttachedOutboundOptions;
548	}): ChannelPlugin<TResolvedAccount, Probe, Audit> {
549	  return {
550	    ...params.base,
551	    conversationBindings: {
552	      supportsCurrentConversationBinding: true,
553	      ...params.base.conversationBindings,
554	    },
555	    ...(params.security ? { security: resolveChatChannelSecurity(params.security) } : {}),
556	    ...(params.pairing ? { pairing: resolveChatChannelPairing(params.pairing) } : {}),
557	    ...(params.threading ? { threading: resolveChatChannelThreading(params.threading) } : {}),
558	    ...(params.outbound ? { outbound: resolveChatChannelOutbound(params.outbound) } : {}),
559	  } as ChannelPlugin<TResolvedAccount, Probe, Audit>;
560	}
561	
562	// Shared base object for channel plugins that only need to override a few optional surfaces.
563	export function createChannelPluginBase<TResolvedAccount>(
564	  params: CreateChannelPluginBaseOptions<TResolvedAccount>,
565	): CreatedChannelPluginBase<TResolvedAccount> {
566	  return {
567	    id: params.id,
568	    meta: {
569	      ...getChatChannelMeta(params.id as Parameters<typeof getChatChannelMeta>[0]),
570	      ...params.meta,
571	    },
572	    ...(params.setupWizard ? { setupWizard: params.setupWizard } : {}),
573	    ...(params.capabilities ? { capabilities: params.capabilities } : {}),
574	    ...(params.agentPrompt ? { agentPrompt: params.agentPrompt } : {}),
575	    ...(params.streaming ? { streaming: params.streaming } : {}),
576	    ...(params.reload ? { reload: params.reload } : {}),
577	    ...(params.gatewayMethods ? { gatewayMethods: params.gatewayMethods } : {}),
578	    ...(params.configSchema ? { configSchema: params.configSchema } : {}),
579	    ...(params.config ? { config: params.config } : {}),
580	    ...(params.security ? { security: params.security } : {}),
581	    ...(params.groups ? { groups: params.groups } : {}),
582	    setup: params.setup,
583	  } as CreatedChannelPluginBase<TResolvedAccount>;
584	}
