64	function buildChatChannelMetaById(): Record<ChatChannelId, ChatChannelMeta> {
65	  const entries = new Map<ChatChannelId, ChatChannelMeta>();
66	
67	  for (const entry of listBundledPluginMetadata({
68	    includeChannelConfigs: true,
69	    includeSyntheticChannelConfigs: false,
70	  })) {
71	    const channel =
72	      entry.packageManifest && "channel" in entry.packageManifest
73	        ? entry.packageManifest.channel
74	        : undefined;
75	    if (!channel) {
76	      continue;
77	    }
78	    const rawId = channel?.id?.trim();
79	    if (!rawId || !CHAT_CHANNEL_ID_SET.has(rawId)) {
80	      continue;
81	    }
82	    const id = rawId as ChatChannelId;
83	    entries.set(
84	      id,
85	      toChatChannelMeta({
86	        id,
87	        channel,
88	      }),
89	    );
90	  }
91	
92	  const missingIds = CHAT_CHANNEL_ORDER.filter((id) => !entries.has(id));
93	  if (missingIds.length > 0) {
94	    throw new Error(`Missing bundled chat channel metadata for: ${missingIds.join(", ")}`);
95	  }
96	
97	  return Object.freeze(Object.fromEntries(entries)) as Record<ChatChannelId, ChatChannelMeta>;
98	}
99	
100	const CHAT_CHANNEL_META = buildChatChannelMetaById();
101	
102	export const CHAT_CHANNEL_ALIASES: Record<string, ChatChannelId> = Object.freeze(
103	  Object.fromEntries(
104	    Object.values(CHAT_CHANNEL_META)
105	      .flatMap((meta) =>
106	        (meta.aliases ?? []).map((alias) => [alias.trim().toLowerCase(), meta.id] as const),
107	      )
108	      .filter(([alias]) => alias.length > 0)
109	      .toSorted(([left], [right]) => left.localeCompare(right)),
110	  ),
111	) as Record<string, ChatChannelId>;
112	
113	function normalizeChannelKey(raw?: string | null): string | undefined {
114	  const normalized = raw?.trim().toLowerCase();
115	  return normalized || undefined;
116	}
117	
118	export function listChatChannels(): ChatChannelMeta[] {
119	  return CHAT_CHANNEL_ORDER.map((id) => CHAT_CHANNEL_META[id]);
120	}
121	
122	export function listChatChannelAliases(): string[] {
123	  return Object.keys(CHAT_CHANNEL_ALIASES);
124	}
125	
126	export function getChatChannelMeta(id: ChatChannelId): ChatChannelMeta {
127	  return CHAT_CHANNEL_META[id];
128	}
129	
130	export function normalizeChatChannelId(raw?: string | null): ChatChannelId | null {
131	  const normalized = normalizeChannelKey(raw);
132	  if (!normalized) {
133	    return null;
134	  }
135	  const resolved = CHAT_CHANNEL_ALIASES[normalized] ?? normalized;
136	  return CHAT_CHANNEL_ORDER.includes(resolved) ? resolved : null;
137	}
