### 2. openclaw.plugin.json

**Location:** `/extensions/{plugin-id}/openclaw.plugin.json`

**Purpose:** Runtime plugin manifest (minimal and static).

**Structure:**
```json
{
  "id": "{plugin-id}",
  "channels": ["{plugin-id}"],
  "configSchema": {
    "type": "object",
    "additionalProperties": false,
    "properties": {}
  }
}
```

**Both IRC and Nostr use identical minimal structure:**
- `id`: Must match package.json channel.id
- `channels`: Array listing supported channel IDs
- `configSchema`: Empty object (schema defined elsewhere, typically in `src/channel.ts`)

---

### 3. index.ts (Main Plugin Entry)

**Location:** `/extensions/{plugin-id}/index.ts`

**Purpose:** Main entry point that exports the channel plugin and runtime setup.

**Structure Pattern:**
```typescript
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
import { {pluginName}Plugin } from "./src/channel.js";
import { set{PluginName}Runtime } from "./src/runtime.js";

export { {pluginName}Plugin } from "./src/channel.js";
export { set{PluginName}Runtime } from "./src/runtime.js";

export default defineChannelPluginEntry({
  id: "{plugin-id}",
  name: "{Display Name}",
  description: "{Plugin description}",
  plugin: {pluginName}Plugin as ChannelPlugin,
  setRuntime: set{PluginName}Runtime,
  registerFull?: (api) => { /* optional */ }  // Nostr example only
});
```

**IRC Example:**
```typescript
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
import { ircPlugin } from "./src/channel.js";
import { setIrcRuntime } from "./src/runtime.js";

export { ircPlugin } from "./src/channel.js";
export { setIrcRuntime } from "./src/runtime.js";

export default defineChannelPluginEntry({
  id: "irc",
  name: "IRC",
  description: "IRC channel plugin",
  plugin: ircPlugin as ChannelPlugin,
  setRuntime: setIrcRuntime,
});
```

**Nostr Example (with registerFull):**
```typescript
import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
import { nostrPlugin } from "./src/channel.js";
import type { NostrProfile } from "./src/config-schema.js";
import { createNostrProfileHttpHandler } from "./src/nostr-profile-http.js";
import { getNostrRuntime, setNostrRuntime } from "./src/runtime.js";
import { resolveNostrAccount } from "./src/types.js";

export { nostrPlugin } from "./src/channel.js";
export { setNostrRuntime } from "./src/runtime.js";

export default defineChannelPluginEntry({
  id: "nostr",
  name: "Nostr",
  description: "Nostr DM channel plugin via NIP-04",
  plugin: nostrPlugin,
  setRuntime: setNostrRuntime,
  registerFull(api) {
    // Optional: register HTTP routes, metrics, etc.
    const httpHandler = createNostrProfileHttpHandler({...});
    api.registerHttpRoute({
      path: "/api/channels/nostr",
      auth: "gateway",
      match: "prefix",
      handler: httpHandler,
    });
  },
});
```

