### 7. src/channel.ts (Core Plugin Definition)

**Location:** `/extensions/{plugin-id}/src/channel.ts`

**Purpose:** Main channel plugin implementation using `createChatChannelPlugin`.

**Macro Structure:**
```typescript
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import { ... other imports ... } from "openclaw/plugin-sdk/...";

// Helper functions and adapters

export const {pluginName}Plugin: ChannelPlugin<Resolved{PluginName}Account, OptionalProbeType> = 
  createChatChannelPlugin({
    base: { /* base capabilities and config */ },
    pairing?: { /* pairing configuration */ },
    security?: { /* security policies */ },
    outbound?: { /* message sending */ },
  });
```

**A. Base Configuration:**
```typescript
base: {
  id: "{plugin-id}",
  meta: {
    id: "{plugin-id}",
    label: "{Display Name}",
    selectionLabel?: "{User selection text}",
    detailLabel?: "{Detail text}",
    docsPath: "/channels/{plugin-id}",
    docsLabel: "{plugin-id}",
    blurb: "{Description}",
    order?: number,
